// Mode: Run Once for All Items

const filenames = $input.all().map(item => {
  const name = item.json.name;
  // Remove ANY extension (everything after the last dot)
  return name.replace(/\.[^/.]+$/, '');
});

return [{ json: { filenames } }];

// Mode: Run Once for All Items

// Use $input for sheet rows (node 4 is directly after Read Sheet)
const sheetRows = $input.all();

// ?? Replace 'Extract Filenames' with your EXACT node name from the canvas
const driveFiles = $('Extract Filenames2').first().json.filenames;

// DEBUG - open browser console to see these
console.log('Sheet row count:', sheetRows.length);
console.log('Drive files looking for:', JSON.stringify(driveFiles));
console.log('First sheet Id value:', sheetRows[0]?.json['Id']);

const filenameSet = new Set(driveFiles);

const matches = sheetRows
  .filter(row => filenameSet.has(row.json['Id']))
  .map(row => ({
    json: {
      rowIndex: row.json['row_number'],
      Id: row.json['Id'],
    }
  }));

console.log('Matches found:', matches.length);

return matches;

